159: func (m *SeedAssignmentOnCallAccessMigrator) Exec(sess *xorm.Session, mig *migrator.Migrator) error {
160: 	// Check if the migration is necessary
161: 	hasEntry := 0
162: 	if _, err := sess.SQL(`SELECT 1 FROM seed_assignment LIMIT 1`).Get(&hasEntry); err != nil {
163: 		return err
164: 	}
165: 	if hasEntry == 0 {
166: 		// Skip migration the seed assignment table has not been populated
167: 		// Hence the oncall access permission can be granted without any risk
168: 		return nil
169: 	}
170: 
171: 	// Check if the permission has not already been seeded
172: 	// This is the case for instances that activated the accessControlOnCall feature already.
173: 	type SeedAssignment struct {
174: 		BuiltinRole, Action, Scope, Origin string
175: 	}
176: 	assigns := []SeedAssignment{}
177: 	err := sess.SQL(`SELECT builtin_role, action, scope, origin FROM seed_assignment WHERE action = ? AND scope = ?`,
178: 		"plugins.app:access", "plugins:id:grafana-oncall-app").
179: 		Find(&assigns)
180: 	if err != nil {
181: 		return err
182: 	}
183: 
184: 	basicRoles := map[string]bool{"Viewer": true, "Editor": true, "Admin": true, "Grafana Admin": true}
185: 	for i := range assigns {
186: 		delete(basicRoles, assigns[i].BuiltinRole)
187: 	}
188: 	if len(basicRoles) == 0 {
189: 		return nil
190: 	}
191: 
192: 	// By default, basic roles have access to all app plugins; no need for extra permission.
193: 	// Mark OnCall Access permission as already seeded to prevent it from being added to basic roles.
194: 	toSeed := []SeedAssignment{}
195: 	for br := range basicRoles {
196: 		toSeed = append(toSeed, SeedAssignment{
197: 			BuiltinRole: br,
198: 			Action:      "plugins.app:access",
199: 			Scope:       "plugins:id:grafana-oncall-app",
200: 			Origin:      "grafana-oncall-app",
201: 		})
202: 	}
203: 	_, err = sess.Table("seed_assignment").InsertMulti(&toSeed)
204: 	return err
205: }
