105: func getRedirectToQueryParam(c *contextmodel.ReqContext) string {
106: 	redirectTo := c.Req.RequestURI
107: 	if setting.AppSubUrl != "" && strings.HasPrefix(redirectTo, setting.AppSubUrl) {
108: 		redirectTo = strings.TrimPrefix(redirectTo, setting.AppSubUrl)
109: 	}
110: 
111: 	if redirectTo == "/" {
112: 		return ""
113: 	}
114: 
115: 	// remove any forceLogin=true params
116: 	redirectTo = RemoveForceLoginParams(redirectTo)
